  "Thieves' Tools": {"category":"Manufacturing","type":"Adventuring Gear","rarity":"Mundane","attunement":"No","baseDC":15,"baseTime":250,"requiredCheck":"Tinker's Tools","marketValue":"25 gp","components":["Fine Steel Picks & Files (1 lb)"],"stats":"Used to pick locks and disarm traps."},
  "Keyebob": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Eye]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[EYE EFFECTS]\n• Aberration/Celestial/Elemental/Fey/Fiend/Undead: Gain a detection sense (Uncommon 10 ft. | Rare 20 ft. | Very Rare 60 ft. | Legendary 180 ft.).\n• Beast/Dragon: Gain a bonus to Perception or Intimidation (Uncommon +1 | Rare +2 | Very Rare +3 | Legendary +4).\n• Monstrosity: Gain/extend Darkvision (Uncommon 30 ft. | Rare 60 ft. | Very Rare 90 ft. | Legendary 120 ft.)."},
  "Tempura": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Fat]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[FAT EFFECTS]\nReduces specific elemental damage taken by: Uncommon 1d4 | Rare 1d6 | Very Rare 1d8 | Legendary 1d10.\n• Damage Type: Aberration (Psychic), Beast (Cold), Celestial (Radiant), Construct (Lightning), Dragon/Giant (Breath Type), Fey/Plant (Poison), Fiend (Fire), Monstrosity (Thunder), Ooze (Acid), Undead (Necrotic)."},
  "Steak": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Flesh]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[FLESH EFFECTS]\nThe first hit you make each turn deals bonus elemental damage matching the creature's Fat element.\n• Bonus Damage: Uncommon +1 | Rare +2 | Very Rare +3 | Legendary +4."},
  "Blood Curd": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Blood]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[BLOOD EFFECTS]\nThe first hit you make each turn against the *same creature type* as the blood consumed deals bonus damage of your weapon's type.\n• Bonus Damage: Uncommon 1d4 | Rare 1d6 | Very Rare 1d8 | Legendary 1d10."},
  "Bone Broth": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Bone]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[BONE EFFECTS]\nGain Advantage on saves against specific conditions based on creature type (Aberration: Stunned, Beast: Blinded, Construct: Exhaustion, Dragon: Frightened, Elemental: Weather, Fey: Charmed, Fiend: Poisoned, Giant: Restrained, Humanoid/Undead: Disease, Monstrosity: Paralysed, Plant: Sleep immunity).\n• Celestial: Temp HP/min (1d6 to 4d6).\n• Undead: Instant Heal (1d4+1 to 4d4+4)."},
  "Egg Dumpling": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Egg]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[EGG EFFECTS]\nGain a morphological change based on type (Aberration: tentacle, Beast: Env. saves, Dragon: bite attack, Fey: Chameleon skin, Humanoid: swim/fly speed, Monstrosity: Natural AC)."},
  "Hearty Stew": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Heart]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[HEART EFFECTS]\nYou automatically know the direction of any living (or unliving) hearts of the matching creature type within a radius (Uncommon 60 ft. to Legendary 1 mile)."},
  "Liverwurst": {"category":"Cooking","type":"Meal","rarity":"Novice","attunement":"No","baseDC":12,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"5 gp","components":["1x [Counts as Liver]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\n[LIVER EFFECTS]\nWhen a creature of the matching type hits you with a melee attack, they take necrotic damage (Uncommon 1d4 to Legendary 1d10)."},
  "Tofeye Apple": {"category":"Cooking","type":"Meal","rarity":"Journeyman","attunement":"No","baseDC":16,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"15 gp","components":["1x [Counts as Bone]","1x [Counts as Eye]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\nCombines the Bone and Eye effects scaling to the rarity of the materials used."},
  "Dwarven Scotch": {"category":"Cooking","type":"Meal","rarity":"Journeyman","attunement":"No","baseDC":16,"baseTime":1,"requiredCheck":"Constitution (Cook's Utensils)","marketValue":"15 gp","components":["1x [Counts as Egg]","1x [Counts as Flesh]"],"stats":"Yield: 1 Large or 4 Medium portions.\nDuration: 8 hours.\n\nCombines the Egg and Flesh effects scaling to the rarity of the materials used."},
